    CACHE 1;

ALTER SEQUENCE public.answer_log_id_seq OWNER TO interview_db_kmnb_user;
ALTER SEQUENCE public.answer_log_id_seq OWNED BY public.answer_log.id;


CREATE TABLE public.answer_keyword_result (
                                              id bigint NOT NULL,
                                              answer_id bigint NOT NULL,
                                              keyword_id bigint NOT NULL,
                                              similarity_score integer NOT NULL,
                                              is_covered boolean NOT NULL,
                                              reason text NOT NULL
);

ALTER TABLE public.answer_keyword_result OWNER TO interview_db_kmnb_user;

CREATE SEQUENCE public.answer_keyword_result_id_seq
