ALTER TABLE ONLY public.answer_log ALTER COLUMN id SET DEFAULT nextval('public.answer_log_id_seq'::regclass);


ALTER TABLE ONLY public.answer_keyword_result ALTER COLUMN id SET DEFAULT nextval('public.answer_keyword_result_id_seq'::regclass);

ALTER TABLE ONLY public.follow_up_answer ALTER COLUMN id SET DEFAULT nextval('public.follow_up_answer_id_seq'::regclass);

ALTER TABLE ONLY public.review_state ALTER COLUMN id SET DEFAULT nextval('public.review_state_id_seq'::regclass);










